        rowlen = len(grid)
        collen = len(grid[0])
        magic_count = 0

        for row in range(rowlen - 2):
            for col in range(collen - 2):
                mag = [grid[row+i][col:col+3] for i in range(3)]
                if is_magic(mag):
                    magic_count += 1

